import { makeStyles } from '@material-ui/core/styles';

const useStyles = makeStyles((theme) => ({
  homeContainer: {
    position: 'absolute', // Använd 'absolute' istället för 'relative'
    top: 0,              // Placera högst upp på sidan
    left: 0,
    width: '100%',       // Ta upp hela bredden
    height: '100vh',     // Ta upp hela höjden av vyhöjden
    zIndex: 0,
  },
    hero: {
        display: 'flex',
        height: '100vh', // 100% of the viewport height
        overflow: 'hidden',
      },
      heroImageContainer: {
        position: 'fixed',
        top: 0,
        left: 0,
        width: '100%',
        height: '100vh',
        zIndex: -1, // Set z-index to make sure it's behind other elements
        overflow: 'hidden',
      },
      heroImage: {
        width: '100%',
        height: '100%',
        objectFit: 'cover',
      },
      heroContentContainer: {
        flex: '1',
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center',
        alignItems: 'center',
      },
      heroContent: {
        textAlign: 'center',
      },
      heroWelcome: {
        fontSize: '2.5rem',
        fontWeight: 'bold',
        marginBottom: theme.spacing(2),
      },
      heroCTA: {
        '&:hover': {
          backgroundColor: theme.palette.primary.dark,
        },
      },
      contentContainer: {
          position: 'absolute',
          top: '50%',
          left: '50%',
          transform: 'translate(-50%, -50%)',
          textAlign: 'center',
        },
      
        welcomeText: {
          marginBottom: theme.spacing(3),
        },
      
        readMoreButton: {
          color: 'white',
          borderColor: 'white',
          '&:hover': {
            color: 'black',
          },
        },
      
        imagesContainer: {
          position: 'relative',
          display: 'flex',
          justifyContent: 'center',
          alignItems: 'center',
        },
      
        bottomImage: {
          width: '100%',
          height: 'auto',
          position: 'relative',
          zIndex: 1,
        },
      
        topImage: {
          width: '75%', // Justera efter behov
          height: 'auto',
          position: 'absolute',
          top: '25%', // Justera efter behov
          left: '12.5%', // Justera efter behov
          zIndex: 2,
        },
        hello: {
          color: 'white'
        }
}));

export default useStyles;
